import { puzzles } from './data/puzzles';
import { bridgeKey, canAddBridge, computeCurrentCounts, isVictory } from './utils/hashiLogic';

const GRID_SIZE = 40;
const ISLAND_RADIUS = 16;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);
  const [keyboardMode, setKeyboardMode] = useState(false);
  const svgRef = useRef(null);

  const currentPuzzle = puzzles[puzzleIndex];
  const islands = currentPuzzle.islands;

  const resetGame = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIndex(0);
    setError(null);
    setVictory(false);
  }, []);

  useEffect(() => {
    resetGame();
  }, [puzzleIndex, resetGame]);

  useEffect(() => {
    if (bridges.size > 0 && isVictory(islands, bridges)) {
      setVictory(true);
    } else {
      setVictory(false);
    }
  }, [bridges, islands]);

  const handlePuzzleChange = (e) => {
    setPuzzleIndex(Number(e.target.value));
  };

  const handleReset = () => {
    setBridges(new Map());
    setSelectedIsland(null);
    setError(null);
    setVictory(false);
  };

  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const currentCount = bridges.get(key) || 0;

    if (currentCount === 0) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setError(result.error);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setBridges(newBridges);
    } else if (currentCount === 1) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setError(null);
        const newBridges = new Map(bridges);
        newBridges.delete(key);
        setBridges(newBridges);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setBridges(newBridges);
    } else {
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
    }
  }, [bridges, islands]);

  const removeBridgeByKey = useCallback((key) => {
    const currentCount = bridges.get(key) || 0;
    if (currentCount > 0) {
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
    }
  }, [bridges]);

  const handleIslandClick = useCallback((island, e) => {
    if (e.button === 2 || e.ctrlKey) {
      if (selectedIsland !== null) {
        const key = bridgeKey(selectedIsland, island);
        removeBridgeByKey(key);
        setSelectedIsland(null);
      }
      return;
    }

    if (selectedIsland === null) {
      setSelectedIsland(island);
      setError(null);
    } else {
      if (selectedIsland.id === island.id) {
        setSelectedIsland(null);
        return;
      }
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge, removeBridgeByKey]);

  const handleBridgeClick = useCallback((key, e) => {
    if (e.button === 2 || e.ctrlKey) {
      e.preventDefault();
      e.stopPropagation();
      removeBridgeByKey(key);
      setSelectedIsland(null);
    }
  }, [removeBridgeByKey]);

  const handleBridgeContextMenu = useCallback((key, e) => {
    e.preventDefault();
    e.stopPropagation();
    removeBridgeByKey(key);
    setSelectedIsland(null);
  }, [removeBridgeByKey]);

  const handleContextMenu = useCallback((e) => {
    e.preventDefault();
  }, []);

  const findNextIsland = useCallback((direction) => {
    const current = islands[cursorIndex];
    let candidates = [];

    for (let i = 0; i < islands.length; i++) {
      if (i === cursorIndex) continue;
      const other = islands[i];
      switch (direction) {
        case 'ArrowUp':
          if (other.y < current.y) candidates.push(i);
          break;
        case 'ArrowDown':
          if (other.y > current.y) candidates.push(i);
          break;
        case 'ArrowLeft':
          if (other.x < current.x) candidates.push(i);
          break;
        case 'ArrowRight':
          if (other.x > current.x) candidates.push(i);
          break;
      }
    }

    if (candidates.length === 0) return cursorIndex;

    candidates.sort((a, b) => {
      const da = Math.abs(islands[a].x - current.x) + Math.abs(islands[a].y - current.y);
      const db = Math.abs(islands[b].x - current.x) + Math.abs(islands[b].y - current.y);
      return da - db;
    });

    return candidates[0];
  }, [cursorIndex, islands]);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
        e.preventDefault();
        setKeyboardMode(true);
        const next = findNextIsland(e.key);
        setCursorIndex(next);
      } else if (e.key === 'Enter') {
        e.preventDefault();
        setKeyboardMode(true);
        const cursorIsland = islands[cursorIndex];
        if (selectedIsland === null) {
          setSelectedIsland(cursorIsland);
          setError(null);
        } else {
          if (selectedIsland.id === cursorIsland.id) {
            setSelectedIsland(null);
            return;
          }
          toggleBridge(selectedIsland, cursorIsland);
          setSelectedIsland(null);
        }
      } else if (e.key === 'Escape') {
        e.preventDefault();
        setSelectedIsland(null);
        setError(null);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIndex, selectedIsland, islands, findNextIsland, toggleBridge]);

  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges.entries()) {
      if (count === 0) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const px1 = x1 * GRID_SIZE;
      const py1 = y1 * GRID_SIZE;
      const px2 = x2 * GRID_SIZE;
      const py2 = y2 * GRID_SIZE;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1} y1={py1}
            x2={px2} y2={py2}
            stroke="#0f0"
            strokeWidth="2"
            style={{ cursor: 'pointer' }}
            onClick={(e) => handleBridgeClick(key, e)}
            onContextMenu={(e) => handleBridgeContextMenu(key, e)}
          />
        );
      } else if (count === 2) {
        const isHorizontal = y1 === y2;
        const offset = 4;
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1} y1={py1 - offset}
              x2={px2} y2={py2 - offset}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1} y1={py1 + offset}
              x2={px2} y2={py2 + offset}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
            />
          );
        } else {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1 - offset} y1={py1}
              x2={px2 - offset} y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1 + offset} y1={py1}
              x2={px2 + offset} y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              style={{ cursor: 'pointer' }}
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
            />
          );
        }
      }
    }
    return lines;
  };

  const renderIslands = () => {
    return islands.map((island) => {
      const px = island.x * GRID_SIZE;
      const py = island.y * GRID_SIZE;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}
           onMouseDown={(e) => handleIslandClick(island, e)}
           onContextMenu={(e) => {
             e.preventDefault();
             e.stopPropagation();
             if (selectedIsland !== null) {
               const bkey = bridgeKey(selectedIsland, island);
               removeBridgeByKey(bkey);
               setSelectedIsland(null);
             }
           }}
           style={{ cursor: 'pointer' }}>
          <circle
            cx={px}
            cy={py}
            r={ISLAND_RADIUS}
            fill="black"
            stroke={isSelected ? '#ff0' : '#0f0'}
            strokeWidth={isSelected ? 3 : 2}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
            style={{ pointerEvents: 'none' }}
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  const renderCursor = () => {
    if (!keyboardMode) return null;
    const island = islands[cursorIndex];
    if (!island) return null;
    const px = island.x * GRID_SIZE;
    const py = island.y * GRID_SIZE;
    const size = ISLAND_RADIUS + 6;

    return (
      <rect
        x={px - size}
        y={py - size}
        width={size * 2}
        height={size * 2}
        fill="none"
        stroke="#0ff"
        strokeWidth="2"
        strokeDasharray="4 2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div onContextMenu={handleContextMenu} style={{ margin: 0, padding: 0 }}>
      <div style={{ padding: '8px', display: 'flex', gap: '12px', alignItems: 'center' }}>
        <select value={puzzleIndex} onChange={handlePuzzleChange}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', padding: '4px' }}>
          {puzzles.map((p, i) => (
            <option key={p.id} value={i}>{p.name}</option>
          ))}
        </select>
        <button onClick={handleReset}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', padding: '4px 8px', cursor: 'pointer' }}>
          Reset
        </button>
        {error && <span className="error-message" style={{ color: '#f00', fontFamily: 'monospace' }}>{error}</span>}
        {victory && <span className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', fontSize: '20px', fontWeight: 'bold' }}>SOLVED!</span>}
      </div>
      <svg ref={svgRef} width="800" height="600" style={{ display: 'block' }}>
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
"""

